mapper.select:
SELECT c.*, p1.category_nm AS parent_category_nm, p2.category_nm AS grand_parent_category_nm, cd_cs.code_label AS category_status_cd_nm FROM pd_category c LEFT JOIN pd_category p1 ON p1.category_id = c.parent_category_id LEFT JOIN pd_category p2 ON p2.category_id = p1.parent_category_id LEFT JOIN sy_code cd_cs ON cd_cs.code_grp = 'USE_YN' AND cd_cs.code_value = c.category_status_cd
ORDER BY c.category_id ASC ORDER BY c.category_id DESC ORDER BY c.category_nm ASC ORDER BY c.category_nm DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.category_depth ASC, c.sort_ord ASC, c.reg_date ASC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT c.*, p1.category_nm AS parent_category_nm, p2.category_nm AS grand_parent_category_nm, cd_cs.code_label AS category_status_cd_nm FROM pd_category c LEFT JOIN pd_category p1 ON p1.category_id = c.parent_category_id LEFT JOIN pd_category p2 ON p2.category_id = p1.parent_category_id LEFT JOIN sy_code cd_cs ON cd_cs.code_grp = 'USE_YN' AND cd_cs.code_value = c.category_status_cd
ORDER BY c.category_id ASC ORDER BY c.category_id DESC ORDER BY c.category_nm ASC ORDER BY c.category_nm DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.category_depth ASC, c.sort_ord ASC, c.reg_date ASC
LIMIT #{p.limit} OFFSET #{p.offset}

mapper.update:
UPDATE pd_category
category_nm = #{categoryNm}, category_status_cd = #{categoryStatusCd}, category_status_cd_before = #{categoryStatusCdBefore}, sort_ord = #{sortOrd}, img_url = #{imgUrl}, category_desc = #{categoryDesc}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE category_id = #{categoryId}
